module RefModule (
    input clk,
    input rst_n,
    input load_en,
    input [15:0] data_in,
    output reg [15:0] data_out
);
  wire _tap_clk = clk & {1{1'b1}};


    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            data_out <= 16'b0000000000000000;
        end else if (load_en) begin
            data_out <= data_in;
        end
    end
endmodule
